```typescript
// src/main.ts
import { startDashboard } from './dashboard/server';

async function runAutoIteration() {
  const args = process.argv.slice(2);

  // 解析参数
  let intervalSec = 60;
  let maxIterations = 0;
  let enableDashboard = false; // 🆕

  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--interval' && args[i + 1]) {
      intervalSec = parseInt(args[i + 1]);
    } else if (args[i] === '--max' && args[i + 1]) {
      maxIterations = parseInt(args[i + 1]);
    } else if (args[i] === '--enable-dashboard') { // 🆕
      enableDashboard = true;
    }
  }

  // 🆕 启动 Dashboard
  let dashboardServer: any = null;
  if (enableDashboard) {
    try {
      console.log('🚀 启动 Web Dashboard...');
      dashboardServer = await startDashboard();
      console.log('✅ Dashboard 已启动: http://localhost:3000');
    } catch (error) {
      console.error('❌ Dashboard 启动失败:', error);
      // 不阻塞主流程
    }
  }

  // ... 其余代码 ...
}
```

