// src/dashboard/routes/iterations.ts
export async function registerIterationRoutes(
  fastify: FastifyInstance,
  service: IterationService
) {
  // GET /api/v1/iterations - 获取迭代列表（分页）
  fastify.get('/iterations', async (request, reply) => {
    const { page = 1, pageSize = 20, status } = request.query as any;
    const result = await service.list({
      page: Number(page),
      pageSize: Number(pageSize),
      status
    });
    return result;
  });

  // GET /api/v1/iterations/:id - 获取迭代详情
  fastify.get('/iterations/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    const iteration = await service.getById(Number(id));
    if (!iteration) {
      return reply.status(404).send({ error: 'Iteration not found' });
    }
    return iteration;
  });

  // GET /api/v1/iterations/current - 获取当前运行迭代
  fastify.get('/iterations/current', async (request, reply) => {
    const iteration = await service.getCurrentIteration();
    return iteration || null;
  });
}
```

