1. **Iteration Store 监听事件**
```typescript
// dashboard/src/stores/iteration.ts
import { defineStore } from 'pinia'
import { ref } from 'vue'
import { useWebSocketStore } from './websocket'

export const useIterationStore = defineStore('iteration', () => {
  const iterations = ref<Iteration[]>([])
  const currentIteration = ref<IterationDetailResponse | null>(null)
  const total = ref(0)
  const loading = ref(false)
  const error = ref<string | null>(null)

  const wsStore = useWebSocketStore()

  // 🆕 监听 WebSocket 事件
  function setupWebSocketListeners() {
    // 迭代开始
    wsStore.on('iteration.started', (data: any) => {
      console.log('[Iteration] 迭代开始:', data)
      currentIteration.value = data
      iterations.value.unshift(data)
    })

    // 迭代进度更新
    wsStore.on('iteration.progress', (data: any) => {
      console.log('[Iteration] 进度更新:', data)
      if (currentIteration.value) {
        currentIteration.value.progress = data.progress
      }
    })

    // 迭代完成
    wsStore.on('iteration.completed', (data: any) => {
      console.log('[Iteration] 迭代完成:', data)
      if (currentIteration.value) {
        currentIteration.value.status = 'completed'
        currentIteration.value.progress = 100
      }
    })

    // 迭代失败
    wsStore.on('iteration.failed', (data: any) => {
      console.error('[Iteration] 迭代失败:', data)
      if (currentIteration.value) {
        currentIteration.value.status = 'failed'
      }
    })
  }

  // 初始化时设置监听
  function init() {
    setupWebSocketListeners()
  }

  return {
    iterations,
    currentIteration,
    total,
    loading,
    error,
    fetchIterations,
    fetchIterationById,
    fetchCurrentIteration,
    init // 🆕
  }
})
```

2. **Agent Store 监听事件**
```typescript
// dashboard/src/stores/agent.ts
export const useAgentStore = defineStore('agent', () => {
  const agents = ref<Agent[]>([])

  const wsStore = useWebSocketStore()

  // 🆕 监听 Agent 事件
  function setupWebSocketListeners() {
    // Agent 任务完成
    wsStore.on('agent.task_completed', (data: any) => {
      console.log('[Agent] 任务完成:', data)
      updateAgentStatus(data.agentName, 'completed')
    })

    // Agent 状态变化
    wsStore.on('agent.status_changed', (data: any) => {
      console.log('[Agent] 状态变化:', data)
      updateAgent(data)
    })
  }

  function updateAgent(agentData: Partial<Agent>) {
    const agent = agents.value.find(a => a.name === agentData.name)
    if (agent) {
      Object.assign(agent, agentData)
    }
  }

  function init() {
    setupWebSocketListeners()
  }

  return {
    agents,
    initAgents,
    updateAgent,
    init // 🆕
  }
})
```

